 87→function truncateContent(content: string, maxLength: number): string {
 88→  const singleLine = content.replace(/\n/g, ' ');
 89→  if (singleLine.length <= maxLength) return singleLine;
 90→  return singleLine.slice(0, maxLength) + '\u2026';
