142→function EditSnippetView({ snippet, onSubmit }: EditSnippetViewProps) {
143→  const [form, setForm] = useState<SnippetFormState>(() => {
144→    if (snippet) {
145→      return {
146→        name: snippet.name,
147→        keyword: snippet.keyword,
148→        snippet: snippet.content,
149→        category: snippet.category,
150→        tags: snippet.tags.map(t => t.text.toLowerCase()),
151→      };
152→    }
153→    return INITIAL_SNIPPET_FORM;
154→  });
155→  const [errors, setErrors] = useState<
156→    Partial<Record<keyof SnippetFormState, string>>
157→  >({});
158→
159→  const handleSubmit = useCallback(() => {
160→    const newErrors: Partial<Record<keyof SnippetFormState, string>> = {};
161→    if (!form.name.trim()) {
162→      newErrors.name = 'Name is required';
163→    }
164→    if (!form.snippet.trim()) {
165→      newErrors.snippet = 'Snippet content is required';
166→    }
167→    setErrors(newErrors);
168→    if (Object.keys(newErrors).length > 0) return;
169→    onSubmit(form);
170→  }, [
171→    form,
172→    onSubmit,
173→  ]);
174→
175→  useKeyboardShortcut(
176→    {
177→      key: 'Enter',
178→      meta: true,
179→    },
180→    handleSubmit,
181→  );
182→
183→  return (
