190→            ...prev,
191→            name: v,
192→          }))
193→        }
194→        placeholder="e.g. Email Signature"
195→        error={errors.name}
196→        autoFocus
197→      />
198→      <FormTextField
199→        label="Keyword"
200→        value={form.keyword}
201→        onChange={v =>
202→          setForm(prev => ({
203→            ...prev,
204→            keyword: v,
205→          }))
206→        }
207→        placeholder="e.g. !sig"
208→        description="Type this to expand the snippet"
209→      />
210→      <FormDropdown
211→        label="Category"
212→        value={form.category}
213→        onChange={v =>
214→          setForm(prev => ({
215→            ...prev,
216→            category: v,
217→          }))
218→        }
219→        options={FORM_CATEGORY_OPTIONS}
220→        placeholder="Select a category"
221→      />
222→      <FormTagPicker
223→        label="Tags"
224→        value={form.tags}
225→        onChange={v =>
226→          setForm(prev => ({
227→            ...prev,
228→            tags: v,
229→          }))
230→        }
231→        options={FORM_TAG_OPTIONS}
232→        placeholder="Add tags..."
233→        description="Categorize your snippet with tags"
234→      />
235→      <FormTextArea
236→        label="Snippet"
237→        value={form.snippet}
238→        onChange={v =>
239→          setForm(prev => ({
240→            ...prev,
241→            snippet: v,
242→          }))
243→        }
244→        placeholder="Enter your snippet content..."
245→        error={errors.snippet}
246→        rows={5}
247→      />
248→    </Form>
249→  );
250→}
