254→export function SnippetManagerView() {
255→  const nav = useNavigation();
256→  const [entries, setEntries] = useState<SnippetEntry[]>(MOCK_SNIPPET_ENTRIES);
257→  const [query, setQuery] = useState('');
258→  const [filterValue, setFilterValue] = useState('all');
259→  const [selectedIndex, setSelectedIndex] = useState(0);
260→  const [actionsOpen, setActionsOpen] = useState(false);
261→  const [subView, setSubView] = useState<SnippetSubView>('list');
262→  const [editingSnippet, setEditingSnippet] = useState<
263→    SnippetEntry | undefined
264→  >();
265→  const { items: hudItems, show: showHUD } = useHUD();
266→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
267→  const now = useMemo(() => new Date(), []);
268→
269→  const filtered = useMemo(() => {
270→    let items = entries;
271→    if (filterValue !== 'all') {
272→      items = items.filter(e => e.category === filterValue);
273→    }
274→    if (query) {
275→      const lower = query.toLowerCase();
276→      items = items.filter(
277→        e =>
278→          e.name.toLowerCase().includes(lower) ||
279→          e.keyword.toLowerCase().includes(lower) ||
280→          e.content.toLowerCase().includes(lower),
281→      );
282→    }
283→    return items;
284→  }, [
285→    entries,
286→    query,
287→    filterValue,
288→  ]);
289→
290→  const groupedByCategory = useMemo(() => {
291→    const groups: {
292→      title: string;
293→      items: SnippetEntry[];
294→    }[] = [];
295→    const categoryOrder = [
296→      'code',
297→      'email',
298→      'template',
299→      'general',
300→    ] as const;
301→    const categoryLabels: Record<string, string> = {
302→      code: 'Code',
303→      email: 'Email',
304→      template: 'Template',
305→      general: 'General',
306→    };
307→
308→    for (const cat of categoryOrder) {
309→      const items = filtered.filter(e => e.category === cat);
310→      if (items.length > 0) {
311→        groups.push({
312→          title: categoryLabels[cat]!,
313→          items,
314→        });
315→      }
316→    }
317→    return groups;
318→  }, [filtered]);
319→
320→  const flatItems = useMemo(
321→    () => groupedByCategory.flatMap(g => g.items),
322→    [groupedByCategory],
323→  );
324→  const totalItemCount = flatItems.length;
325→
326→  useEffect(() => {
327→    if (totalItemCount === 0) {
328→      setSelectedIndex(0);
329→    } else {
330→      setSelectedIndex(prev =>
331→        prev >= totalItemCount ? totalItemCount - 1 : prev,
332→      );
333→    }
334→  }, [totalItemCount]);
335→
336→  const selectedEntry = flatItems[selectedIndex];
337→
338→  const handleQueryChange = useCallback((value: string) => {
339→    setQuery(value);
340→    setSelectedIndex(0);
341→    setActionsOpen(false);
342→  }, []);
343→
344→  const handleFilterChange = useCallback((value: string) => {
345→    setFilterValue(value);
346→    setSelectedIndex(0);
347→  }, []);
348→
349→  const handleActiveIndexChange = useCallback((index: number) => {
350→    setSelectedIndex(index);
351→    setActionsOpen(false);
352→  }, []);
353→
354→  const handleInsert = useCallback(() => {
355→    if (!selectedEntry) return;
356→    setActionsOpen(false);
357→    showHUD({
358→      icon: <SnippetHUDIcon />,
359→      title: 'Inserted Snippet',
360→    });
361→  }, [
362→    selectedEntry,
363→    showHUD,
364→  ]);
365→
366→  const handleCopy = useCallback(() => {
367→    if (!selectedEntry) return;
368→    setActionsOpen(false);
369→    showHUD({
370→      icon: <SnippetHUDIcon />,
371→      title: 'Copied to Clipboard',
372→    });
373→  }, [
