    } else if (item.id === 'snippets') {
      push('Snippets', { type: 'snippets' });
      setQuery('');
      setSelectedIndex(0);
    } else if (item.id === 'color-picker') {
      push('Color Picker', { type: 'grid' });
      setQuery('');
      setSelectedIndex(0);
