  useCallback,
  useEffect,
  useMemo,
  useState,
} from 'react';
import type { SnippetEntry } from '../../data/snippet_data';
import {
  MOCK_SNIPPET_ENTRIES,
  SNIPPET_CATEGORIES,
  SNIPPET_TAGS,
