  },
  {
    label: 'Email',
    value: 'email',
  },
  {
    label: 'Template',
    value: 'template',
  },
] as const;

export const SNIPPET_TAGS = [
  {
    label: 'JavaScript',
    value: 'javascript',
    color: 'yellow' as TagColor,
  },
  {
    label: 'TypeScript',
